import vex
from smolagents import CodeAgent, ToolAgent

# Initialize Smolagents
code_agent = CodeAgent(tools=[clinical_tools])

# Vex-wrapped execution
def safe_agent_run(prompt):
    result = code_agent.run(prompt)
    verified = vex.verify(
        result,
        policies=[
            "no_phi_leakage",
            "hipaa_compliant",
            "fda_auditable"
        ],
        context={"patient_id": "deidentified_123"}
    )
    if verified:
        return exec(result.code, safe_globals())
    raise ValueError("Vex blocked non-compliant execution")

response = safe_agent_run("Calculate dosage for 25kg pediatric patient")
